<table><thead><tr><th>Empresa</th><th>Contacto</th><th>Industria</th><th>Puntaje</th><th>Riesgo</th><th>Estado</th><th></th></tr></thead><tbody><?php foreach($leads as $l): ?><tr><td><strong><?=e($l['company_name'])?></strong><small><?=e($l['company_rut'])?></small></td><td><?=e($l['contact_name'])?><small><?=e($l['email'])?></small></td><td><?=e($l['industry'])?></td><td><?=e($l['risk_score'])?></td><td><span class="badge risk <?=str_contains($l['risk_level'],'bajo')?'low':(str_contains($l['risk_level'],'medio')?'mid':'high')?>"><?=e($l['risk_level'])?></span></td><td><span class="badge"><?=e($l['risk_status'])?></span></td><td><a class="btn ghost" href="<?=url('/leads/'.$l['id'])?>">Ver</a></td></tr><?php endforeach; ?></tbody></table>
